{
  "name": "InvoSwift - Modern Invoice Generator",
  "description": "A fast, minimal, and professional invoice generator with real-time preview, PDF export, and local storage persistence.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface InvoiceItem {
  id: string;
  name: string;
  quantity: number;
  rate: number;
  total: number;
}

export interface BusinessDetails {
  name: string;
  address: string;
  email: string;
  phone: string;
  logo?: string;
}

export interface ClientDetails {
  name: string;
  address: string;
  email: string;
}

export type InvoiceTemplate = 'classic' | 'modern' | 'minimal';

export interface Invoice {
  id: string;
  invoiceNumber: string;
  issueDate: string;
  dueDate: string;
  sender: BusinessDetails;
  client: ClientDetails;
  items: InvoiceItem[];
  currency: string;
  taxRate: number;
  discountRate: number;
  notes: string;
  terms: string;
  template: InvoiceTemplate;
  accentColor: string;
}

export interface AppState {
  invoices: Invoice[];
  currentInvoice: Invoice;
  theme: 'light' | 'dark';
}

import React from 'react';
import { Invoice } from './types';

export const CURRENCIES = [
  { code: 'USD', symbol: '$', name: 'US Dollar' },
  { code: 'EUR', symbol: '€', name: 'Euro' },
  { code: 'GBP', symbol: '£', name: 'British Pound' },
  { code: 'INR', symbol: '₹', name: 'Indian Rupee' },
  { code: 'JPY', symbol: '¥', name: 'Japanese Yen' },
];

export const ACCENT_COLORS = [
  { name: 'Blue', value: '#3b82f6' },
  { name: 'Indigo', value: '#6366f1' },
  { name: 'Rose', value: '#f43f5e' },
  { name: 'Emerald', value: '#10b981' },
  { name: 'Orange', value: '#f59e0b' },
  { name: 'Slate', value: '#475569' },
];

export const INITIAL_INVOICE: Invoice = {
  id: 'temp-id',
  invoiceNumber: `INV-${Math.floor(Math.random() * 9000) + 1000}`,
  issueDate: new Date().toISOString().split('T')[0],
  dueDate: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
  sender: {
    name: 'Your Business Name',
    address: '123 Business St, City, Country',
    email: 'hello@business.com',
    phone: '+1 (555) 000-0000',
  },
  client: {
    name: 'Client Name',
    address: '456 Client Rd, Suite 100, City',
    email: 'billing@client.com',
  },
  items: [
    { id: '1', name: 'Web Design Service', quantity: 1, rate: 1200, total: 1200 },
    { id: '2', name: 'Consulting', quantity: 5, rate: 150, total: 750 },
  ],
  currency: '$',
  taxRate: 10,
  discountRate: 0,
  notes: 'Thank you for your business!',
  terms: 'Payment is due within 15 days of the invoice date.',
  template: 'modern',
  accentColor: '#6366f1',
};

export const printInvoice = () => {
  window.print();
};

export const downloadAsJSON = (invoice: any) => {
  const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(invoice, null, 2));
  const downloadAnchorNode = document.createElement('a');
  downloadAnchorNode.setAttribute("href", dataStr);
  downloadAnchorNode.setAttribute("download", `invoice-${invoice.invoiceNumber}.json`);
  document.body.appendChild(downloadAnchorNode);
  downloadAnchorNode.click();
  downloadAnchorNode.remove();
};

import React from 'react';
import { Invoice } from '../types';
import { Plus, Trash2, Eye, Download, FileText, Search } from 'lucide-react';

interface DashboardProps {
  invoices: Invoice[];
  onEdit: (invoice: Invoice) => void;
  onDelete: (id: string) => void;
  onNew: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ invoices, onEdit, onDelete, onNew }) => {
  const [searchTerm, setSearchTerm] = React.useState('');

  const filteredInvoices = invoices.filter(inv => 
    inv.invoiceNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
    inv.client.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
        <div>
          <h1 className="text-3xl font-bold mb-2">Saved Invoices</h1>
          <p className="text-slate-500 dark:text-slate-400">Manage all your locally saved invoice documents.</p>
        </div>
        <button 
          onClick={onNew}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-3 rounded-xl font-semibold flex items-center gap-2 transition-all shadow-lg shadow-indigo-500/20"
        >
          <Plus size={20} />
          Create New Invoice
        </button>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-slate-200 dark:border-slate-800 flex items-center gap-4">
          <div className="relative flex-grow max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Search by ID or client name..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-4 py-2 bg-slate-50 dark:bg-slate-800 border-none rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 transition-all outline-none"
            />
          </div>
        </div>

        {filteredInvoices.length === 0 ? (
          <div className="py-20 text-center">
            <div className="bg-slate-100 dark:bg-slate-800 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
              <FileText size={32} />
            </div>
            <h3 className="text-xl font-semibold mb-2">No Invoices Found</h3>
            <p className="text-slate-500 dark:text-slate-400 mb-6">Start by creating your first professional invoice today.</p>
            <button 
              onClick={onNew}
              className="text-indigo-600 font-semibold hover:underline"
            >
              Create Now &rarr;
            </button>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50/50 dark:bg-slate-800/50 text-xs font-bold uppercase tracking-wider text-slate-500">
                  <th className="px-6 py-4">Number</th>
                  <th className="px-6 py-4">Client</th>
                  <th className="px-6 py-4">Date</th>
                  <th className="px-6 py-4">Total</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                {filteredInvoices.map((inv) => {
                   const subtotal = inv.items.reduce((acc, item) => acc + (item.quantity * item.rate), 0);
                   const tax = subtotal * (inv.taxRate / 100);
                   const discount = subtotal * (inv.discountRate / 100);
                   const total = subtotal + tax - discount;

                   return (
                    <tr key={inv.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors group">
                      <td className="px-6 py-4 font-semibold text-indigo-600">#{inv.invoiceNumber}</td>
                      <td className="px-6 py-4">
                        <div className="font-medium">{inv.client.name}</div>
                        <div className="text-xs text-slate-400">{inv.client.email}</div>
                      </td>
                      <td className="px-6 py-4 text-sm">{inv.issueDate}</td>
                      <td className="px-6 py-4 font-bold">{inv.currency} {total.toLocaleString()}</td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex items-center justify-end gap-2">
                          <button 
                            onClick={() => onEdit(inv)}
                            className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-lg text-slate-500 hover:text-indigo-600 transition-all border border-transparent hover:border-slate-200 dark:hover:border-slate-600"
                            title="Edit"
                          >
                            <Eye size={18} />
                          </button>
                          <button 
                            onClick={() => onDelete(inv.id)}
                            className="p-2 hover:bg-white dark:hover:bg-slate-700 rounded-lg text-slate-500 hover:text-rose-600 transition-all border border-transparent hover:border-slate-200 dark:hover:border-slate-600"
                            title="Delete"
                          >
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </td>
                    </tr>
                   );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { Invoice, InvoiceItem, InvoiceTemplate } from '../types';
import { CURRENCIES, ACCENT_COLORS } from '../constants';
import { Plus, Trash2, Upload, Layout, Palette, Settings, Building2, UserCircle2, ListTodo, FileText, ChevronDown } from 'lucide-react';

interface InvoiceEditorProps {
  invoice: Invoice;
  setInvoice: (invoice: Invoice) => void;
}

const InvoiceEditor: React.FC<InvoiceEditorProps> = ({ invoice, setInvoice }) => {
  const [activeSection, setActiveSection] = React.useState<'business' | 'client' | 'items' | 'styling' | 'extra'>('business');

  const updateItem = (id: string, updates: Partial<InvoiceItem>) => {
    const newItems = invoice.items.map(item => 
      item.id === id ? { ...item, ...updates, total: (updates.quantity || item.quantity) * (updates.rate || item.rate) } : item
    );
    setInvoice({ ...invoice, items: newItems });
  };

  const addItem = () => {
    const newItem: InvoiceItem = {
      id: Math.random().toString(36).substr(2, 9),
      name: '',
      quantity: 1,
      rate: 0,
      total: 0
    };
    setInvoice({ ...invoice, items: [...invoice.items, newItem] });
  };

  const removeItem = (id: string) => {
    setInvoice({ ...invoice, items: invoice.items.filter(i => i.id !== id) });
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setInvoice({ ...invoice, sender: { ...invoice.sender, logo: reader.result as string } });
      };
      reader.readAsDataURL(file);
    }
  };

  const SectionHeader: React.FC<{ id: typeof activeSection; icon: React.ReactNode; label: string }> = ({ id, icon, label }) => (
    <button 
      onClick={() => setActiveSection(activeSection === id ? activeSection : id)}
      className={`w-full flex items-center justify-between p-4 rounded-xl transition-all ${activeSection === id ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'hover:bg-slate-50 dark:hover:bg-slate-800'}`}
    >
      <div className="flex items-center gap-3">
        {icon}
        <span className="font-bold">{label}</span>
      </div>
      <ChevronDown size={20} className={`transition-transform ${activeSection === id ? 'rotate-180' : ''}`} />
    </button>
  );

  return (
    <div className="p-4 md:p-6 space-y-4 max-w-4xl mx-auto pb-24 no-print">

      {/* Quick Settings Bar */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
          <div className="space-y-1">
            <label className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Invoice Number</label>
            <input 
              type="text" 
              value={invoice.invoiceNumber} 
              onChange={(e) => setInvoice({...invoice, invoiceNumber: e.target.value})}
              className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Currency</label>
            <select 
               value={invoice.currency}
               onChange={(e) => setInvoice({...invoice, currency: e.target.value})}
               className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            >
               {CURRENCIES.map(c => <option key={c.code} value={c.symbol}>{c.code} ({c.symbol})</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Date</label>
            <input 
              type="date" 
              value={invoice.issueDate} 
              onChange={(e) => setInvoice({...invoice, issueDate: e.target.value})}
              className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Due Date</label>
            <input 
              type="date" 
              value={invoice.dueDate} 
              onChange={(e) => setInvoice({...invoice, dueDate: e.target.value})}
              className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
      </div>

      {/* Accordion Sections */}
      <div className="space-y-2">
        {/* 1. Business Details */}
        <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
          <SectionHeader id="business" icon={<Building2 size={20} />} label="Business Details" />
          {activeSection === 'business' && (
            <div className="p-6 pt-0 space-y-4 animate-slide-down">
               <div className="flex items-center gap-6 py-4">
                  <div className="relative group">
                    <div className="w-20 h-20 rounded-2xl bg-slate-50 dark:bg-slate-800 border-2 border-dashed border-slate-200 dark:border-slate-700 flex items-center justify-center overflow-hidden">
                       {invoice.sender.logo ? (
                         <img src={invoice.sender.logo} className="w-full h-full object-contain" />
                       ) : (
                         <Upload size={24} className="text-slate-400" />
                       )}
                    </div>
                    <input 
                      type="file" 
                      onChange={handleLogoUpload} 
                      className="absolute inset-0 opacity-0 cursor-pointer" 
                      accept="image/*"
                    />
                  </div>
                  <div>
                    <h4 className="font-bold text-sm">Business Logo</h4>
                    <p className="text-xs text-slate-400">PNG, JPG recommended. Max 2MB.</p>
                  </div>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <input 
                   placeholder="Business Name" 
                   value={invoice.sender.name}
                   onChange={(e) => setInvoice({...invoice, sender: {...invoice.sender, name: e.target.value}})}
                   className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                 />
                 <input 
                   placeholder="Email Address" 
                   value={invoice.sender.email}
                   onChange={(e) => setInvoice({...invoice, sender: {...invoice.sender, email: e.target.value}})}
                   className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                 />
                 <input 
                   placeholder="Phone Number" 
                   value={invoice.sender.phone}
                   onChange={(e) => setInvoice({...invoice, sender: {...invoice.sender, phone: e.target.value}})}
                   className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                 />
                 <textarea 
                   placeholder="Full Address" 
                   rows={2}
                   value={invoice.sender.address}
                   onChange={(e) => setInvoice({...invoice, sender: {...invoice.sender, address: e.target.value}})}
                   className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none col-span-1 md:col-span-2"
                 />
               </div>
            </div>
          )}
        </div>

        {/* 2. Client Details */}
        <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
          <SectionHeader id="client" icon={<UserCircle2 size={20} />} label="Client Details" />
          {activeSection === 'client' && (
            <div className="p-6 pt-0 space-y-4 animate-slide-down">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <input 
                   placeholder="Client Name" 
                   value={invoice.client.name}
                   onChange={(e) => setInvoice({...invoice, client: {...invoice.client, name: e.target.value}})}
                   className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                 />
                 <input 
                   placeholder="Client Email" 
                   value={invoice.client.email}
                   onChange={(e) => setInvoice({...invoice, client: {...invoice.client, email: e.target.value}})}
                   className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                 />
                 <textarea 
                   placeholder="Client Address" 
                   rows={2}
                   value={invoice.client.address}
                   onChange={(e) => setInvoice({...invoice, client: {...invoice.client, address: e.target.value}})}
                   className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none col-span-1 md:col-span-2"
                 />
               </div>
            </div>
          )}
        </div>

        {/* 3. Items */}
        <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
          <SectionHeader id="items" icon={<ListTodo size={20} />} label="Line Items" />
          {activeSection === 'items' && (
            <div className="p-6 pt-0 animate-slide-down">
               <div className="space-y-4 mb-6">
                 {invoice.items.map((item, index) => (
                   <div key={item.id} className="grid grid-cols-12 gap-3 items-start group">
                     <div className="col-span-12 md:col-span-6">
                        <input 
                          placeholder="Item description..." 
                          value={item.name}
                          onChange={(e) => updateItem(item.id, { name: e.target.value })}
                          className="w-full p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                        />
                     </div>
                     <div className="col-span-4 md:col-span-2">
                        <input 
                          type="number" 
                          placeholder="Qty" 
                          value={item.quantity}
                          onChange={(e) => updateItem(item.id, { quantity: parseFloat(e.target.value) || 0 })}
                          className="w-full p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                        />
                     </div>
                     <div className="col-span-5 md:col-span-3">
                        <div className="relative">
                          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-sm">{invoice.currency}</span>
                          <input 
                            type="number" 
                            placeholder="Rate" 
                            value={item.rate}
                            onChange={(e) => updateItem(item.id, { rate: parseFloat(e.target.value) || 0 })}
                            className="w-full p-3 pl-8 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                          />
                        </div>
                     </div>
                     <div className="col-span-3 md:col-span-1 flex items-center justify-end h-12">
                       <button 
                         onClick={() => removeItem(item.id)}
                         className="p-2 text-slate-300 hover:text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg transition-all"
                       >
                         <Trash2 size={20} />
                       </button>
                     </div>
                   </div>
                 ))}
               </div>
               <button 
                 onClick={addItem}
                 className="flex items-center gap-2 text-indigo-600 font-bold px-4 py-2 rounded-xl hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all"
               >
                 <Plus size={20} />
                 Add Line Item
               </button>

               <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-4 border-t border-slate-100 dark:border-slate-800 pt-8">
                  <div className="flex items-center gap-4">
                     <span className="text-sm font-bold w-24">Tax (%)</span>
                     <input 
                       type="number" 
                       value={invoice.taxRate} 
                       onChange={(e) => setInvoice({...invoice, taxRate: parseFloat(e.target.value) || 0})}
                       className="p-2 w-24 bg-slate-50 dark:bg-slate-800/50 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500"
                     />
                  </div>
                  <div className="flex items-center gap-4">
                     <span className="text-sm font-bold w-24">Discount (%)</span>
                     <input 
                       type="number" 
                       value={invoice.discountRate} 
                       onChange={(e) => setInvoice({...invoice, discountRate: parseFloat(e.target.value) || 0})}
                       className="p-2 w-24 bg-slate-50 dark:bg-slate-800/50 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500"
                     />
                  </div>
               </div>
            </div>
          )}
        </div>

        {/* 4. Styling */}
        <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
          <SectionHeader id="styling" icon={<Palette size={20} />} label="Template & Styling" />
          {activeSection === 'styling' && (
            <div className="p-6 pt-0 animate-slide-down space-y-8">
               <div>
                  <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Choose Template</h4>
                  <div className="grid grid-cols-3 gap-4">
                     {(['modern', 'classic', 'minimal'] as InvoiceTemplate[]).map(t => (
                       <button 
                         key={t}
                         onClick={() => setInvoice({...invoice, template: t})}
                         className={`p-4 rounded-xl border-2 transition-all text-center capitalize font-medium ${invoice.template === t ? 'border-indigo-600 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600' : 'border-slate-100 dark:border-slate-800'}`}
                       >
                         {t}
                       </button>
                     ))}
                  </div>
               </div>
               <div>
                  <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Accent Color</h4>
                  <div className="flex flex-wrap gap-4">
                     {ACCENT_COLORS.map(c => (
                       <button 
                         key={c.value}
                         onClick={() => setInvoice({...invoice, accentColor: c.value})}
                         className={`w-10 h-10 rounded-full transition-all border-2 ${invoice.accentColor === c.value ? 'border-slate-900 dark:border-white scale-110' : 'border-transparent'}`}
                         style={{ backgroundColor: c.value }}
                         title={c.name}
                       />
                     ))}
                  </div>
               </div>
            </div>
          )}
        </div>

        {/* 5. Extra */}
        <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
          <SectionHeader id="extra" icon={<Settings size={20} />} label="Notes & Terms" />
          {activeSection === 'extra' && (
            <div className="p-6 pt-0 animate-slide-down space-y-4">
               <div className="space-y-2">
                 <label className="text-xs font-bold text-slate-400 uppercase">Additional Notes</label>
                 <textarea 
                   placeholder="A personal message or bank details..." 
                   rows={3}
                   value={invoice.notes}
                   onChange={(e) => setInvoice({...invoice, notes: e.target.value})}
                   className="w-full p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-transparent focus:border-indigo-500 transition-all outline-none"
                 />
