import React, { useState, useEffect, useCallback } from 'react';
import Layout from './components/Layout';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import InvoiceEditor from './components/InvoiceEditor';
import InvoicePreview from './components/InvoicePreview';
import { Invoice } from './types';
import { INITIAL_INVOICE } from './constants';
import { printInvoice, downloadAsJSON } from './utils/pdf';
import { Download, Printer, Save, Share2, ArrowLeft, RotateCcw } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'landing' | 'editor' | 'dashboard'>('landing');
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [currentInvoice, setCurrentInvoice] = useState<Invoice>(INITIAL_INVOICE);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Load from local storage on mount
  useEffect(() => {
    const savedInvoices = localStorage.getItem('invoswift_invoices');
    const savedTheme = localStorage.getItem('invoswift_theme');
    const savedDraft = localStorage.getItem('invoswift_draft');

    if (savedInvoices) setInvoices(JSON.parse(savedInvoices));
    if (savedTheme) setTheme(savedTheme as 'light' | 'dark');
    if (savedDraft) setCurrentInvoice(JSON.parse(savedDraft));
  }, []);

  // Persist to local storage
  useEffect(() => {
    localStorage.setItem('invoswift_invoices', JSON.stringify(invoices));
  }, [invoices]);

  useEffect(() => {
    localStorage.setItem('invoswift_theme', theme);
    document.documentElement.classList.toggle('dark', theme === 'dark');
  }, [theme]);

  useEffect(() => {
    if (currentInvoice.id === 'temp-id') {
      localStorage.setItem('invoswift_draft', JSON.stringify(currentInvoice));
    }
  }, [currentInvoice]);

  const handleNewInvoice = () => {
    const newInvoice = { ...INITIAL_INVOICE, id: 'temp-id', invoiceNumber: `INV-${Math.floor(Math.random() * 9000) + 1000}` };
    setCurrentInvoice(newInvoice);
    setActiveTab('editor');
  };

  const handleSaveInvoice = () => {
    const idToSave = currentInvoice.id === 'temp-id' ? Math.random().toString(36).substr(2, 9) : currentInvoice.id;
    const invoiceToSave = { ...currentInvoice, id: idToSave };

    setInvoices(prev => {
      const exists = prev.find(inv => inv.id === idToSave);
      if (exists) {
        return prev.map(inv => inv.id === idToSave ? invoiceToSave : inv);
      }
      return [invoiceToSave, ...prev];
    });

    setCurrentInvoice(invoiceToSave);
    alert('Invoice saved successfully to your browser storage!');
  };

  const handleDeleteInvoice = (id: string) => {
    if (confirm('Are you sure you want to delete this invoice? This cannot be undone.')) {
      setInvoices(prev => prev.filter(inv => inv.id !== id));
    }
  };

  const handleEditInvoice = (invoice: Invoice) => {
    setCurrentInvoice(invoice);
    setActiveTab('editor');
  };

  const handleReset = () => {
    if (confirm('Reset all fields to default?')) {
      setCurrentInvoice(INITIAL_INVOICE);
    }
  };

  return (
    <Layout 
      theme={theme} 
      setTheme={setTheme} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
    >
      {activeTab === 'landing' && (
        <LandingPage onCreateClick={handleNewInvoice} />
      )}

      {activeTab === 'dashboard' && (
        <Dashboard 
          invoices={invoices} 
          onEdit={handleEditInvoice} 
          onDelete={handleDeleteInvoice}
          onNew={handleNewInvoice}
        />
      )}

      {activeTab === 'editor' && (
        <div className="flex flex-col lg:flex-row h-[calc(100vh-64px)] overflow-hidden">
          {/* Editor Side */}
          <div className="w-full lg:w-1/2 h-full overflow-y-auto bg-slate-50 dark:bg-slate-950 border-r border-slate-200 dark:border-slate-800">
             <div className="sticky top-0 z-10 bg-slate-50/80 dark:bg-slate-950/80 backdrop-blur-sm p-4 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between no-print">
                <button 
                  onClick={() => setActiveTab('dashboard')}
                  className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-lg text-slate-500 transition-all flex items-center gap-2 text-sm font-medium"
                >
                  <ArrowLeft size={18} />
                  Dashboard
                </button>
                <div className="flex gap-2">
                   <button 
                     onClick={handleReset}
                     className="p-2 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-lg text-slate-500 transition-all"
                     title="Reset Template"
                   >
                     <RotateCcw size={18} />
                   </button>
                   <button 
                     onClick={handleSaveInvoice}
                     className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg text-sm font-bold flex items-center gap-2 shadow-lg shadow-indigo-500/20"
                   >
                     <Save size={18} />
                     Save Draft
                   </button>
                </div>
             </div>
             <InvoiceEditor invoice={currentInvoice} setInvoice={setCurrentInvoice} />
          </div>

          {/* Preview Side */}
          <div className="hidden lg:block w-1/2 h-full relative group">
             <InvoicePreview invoice={currentInvoice} />

             {/* Floating Actions */}
             <div className="absolute top-6 right-6 flex flex-col gap-3 no-print">
                <button 
                  onClick={printInvoice}
                  className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 rounded-2xl shadow-xl hover:scale-105 transition-all text-slate-900 dark:text-white flex items-center gap-3 font-bold"
                >
                  <Printer size={20} className="text-indigo-600" />
                  Print / Download PDF
                </button>
                <button 
                  onClick={() => downloadAsJSON(currentInvoice)}
                  className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 rounded-2xl shadow-xl hover:scale-105 transition-all text-slate-900 dark:text-white flex items-center gap-3 font-bold"
                >
                  <Download size={20} className="text-violet-600" />
                  Export as JSON
                </button>
             </div>
          </div>

          {/* Mobile Preview Toggle Button */}
          <div className="lg:hidden fixed bottom-6 left-1/2 -translate-x-1/2 z-50 flex items-center gap-2 no-print">
            <button 
              onClick={printInvoice}
              className="bg-indigo-600 text-white p-4 rounded-full shadow-2xl active:scale-95 transition-transform"
            >
              <Printer size={24} />
            </button>
            <button 
              onClick={() => alert("Preview is available in the desktop version. Use 'Print' to see mobile view.")}
              className="bg-slate-900 dark:bg-white dark:text-slate-900 text-white p-4 rounded-full shadow-2xl active:scale-95 transition-transform"
            >
              <Share2 size={24} />
            </button>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

