import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import InvoiceEditor from './components/InvoiceEditor';
import InvoicePreview from './components/InvoicePreview';
import { Invoice } from './types';
import { INITIAL_INVOICE } from './constants';
import { printInvoice, downloadAsJSON } from './utils/pdf';
import { Download, Printer, Save, ArrowLeft, RotateCcw } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'landing' | 'editor' | 'dashboard'>('landing');
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [currentInvoice, setCurrentInvoice] = useState<Invoice>(INITIAL_INVOICE);

  useEffect(() => {
    const savedInvoices = localStorage.getItem('easeinvo_invoices');
    const savedTheme = localStorage.getItem('easeinvo_theme');
    const savedDraft = localStorage.getItem('easeinvo_draft');

    if (savedInvoices) setInvoices(JSON.parse(savedInvoices));
    if (savedTheme) setTheme(savedTheme as 'light' | 'dark');
    if (savedDraft) setCurrentInvoice(JSON.parse(savedDraft));
  }, []);

  useEffect(() => {
    localStorage.setItem('easeinvo_invoices', JSON.stringify(invoices));
  }, [invoices]);

  useEffect(() => {
    localStorage.setItem('easeinvo_theme', theme);
    document.documentElement.classList.toggle('dark', theme === 'dark');
  }, [theme]);

  useEffect(() => {
    if (currentInvoice.id === 'temp-id') {
      localStorage.setItem('easeinvo_draft', JSON.stringify(currentInvoice));
    }
  }, [currentInvoice]);

  const handleNewInvoice = () => {
    const newInvoice = { ...INITIAL_INVOICE, id: 'temp-id', invoiceNumber: `INV-${Math.floor(Math.random() * 9000) + 1000}` };
    setCurrentInvoice(newInvoice);
    setActiveTab('editor');
  };

  const handleSaveInvoice = () => {
    const idToSave = currentInvoice.id === 'temp-id' ? Math.random().toString(36).substr(2, 9) : currentInvoice.id;
    const invoiceToSave = { ...currentInvoice, id: idToSave };

    setInvoices(prev => {
      const exists = prev.find(inv => inv.id === idToSave);
      if (exists) {
        return prev.map(inv => inv.id === idToSave ? invoiceToSave : inv);
      }
      return [invoiceToSave, ...prev];
    });

    setCurrentInvoice(invoiceToSave);
    alert('Invoice successfully synchronized with browser storage.');
  };

  const handleDeleteInvoice = (id: string) => {
    if (confirm('Delete this record permanently?')) {
      setInvoices(prev => prev.filter(inv => inv.id !== id));
    }
  };

  const handleEditInvoice = (invoice: Invoice) => {
    setCurrentInvoice(invoice);
    setActiveTab('editor');
  };

  const handleReset = () => {
    if (confirm('Reset to initial template?')) {
      setCurrentInvoice(INITIAL_INVOICE);
    }
  };

  return (
    <Layout 
      theme={theme} 
      setTheme={setTheme} 
      activeTab={activeTab} 
      setActiveTab={setActiveTab}
    >
      {activeTab === 'landing' && (
        <LandingPage onCreateClick={handleNewInvoice} />
      )}

      {activeTab === 'dashboard' && (
        <Dashboard 
          invoices={invoices} 
          onEdit={handleEditInvoice} 
          onDelete={handleDeleteInvoice}
          onNew={handleNewInvoice}
        />
      )}

      {activeTab === 'editor' && (
        <div className="flex flex-col lg:flex-row h-[calc(100vh-64px)] overflow-hidden">
          {/* Editor Side */}
          <div className="w-full lg:w-1/2 h-full overflow-y-auto bg-white dark:bg-black border-r border-gray-100 dark:border-zinc-900">
             <div className="sticky top-0 z-10 bg-white/95 dark:bg-black/95 backdrop-blur-sm p-6 border-b border-gray-50 dark:border-zinc-900 flex items-center justify-between no-print">
                <button 
                  onClick={() => setActiveTab('dashboard')}
                  className="px-4 py-2 hover:bg-gray-100 dark:hover:bg-zinc-900 rounded-full text-black dark:text-white transition-all flex items-center gap-2 text-xs font-black tracking-widest uppercase"
                >
                  <ArrowLeft size={16} />
                  DASHBOARD
                </button>
                <div className="flex gap-4">
                   <button 
                     onClick={handleReset}
                     className="p-2.5 bg-gray-50 dark:bg-zinc-900 hover:bg-black hover:text-white dark:hover:bg-white dark:hover:text-black rounded-full transition-all"
                     title="Reset Template"
                   >
                     <RotateCcw size={18} />
                   </button>
                   <button 
                     onClick={handleSaveInvoice}
                     className="px-6 py-2.5 bg-black dark:bg-white text-white dark:text-black rounded-full text-xs font-black tracking-widest uppercase flex items-center gap-2 hover:opacity-80 transition-all"
                   >
                     <Save size={16} />
                     SAVE DRAFT
                   </button>
                </div>
             </div>
             <div className="p-8">
               <InvoiceEditor invoice={currentInvoice} setInvoice={setCurrentInvoice} />
             </div>
          </div>

          {/* Preview Side */}
          <div className="hidden lg:block w-1/2 h-full relative group">
             <InvoicePreview invoice={currentInvoice} />

             {/* Floating Actions */}
             <div className="absolute bottom-10 right-10 flex flex-col gap-4 no-print">
                <button 
                  onClick={printInvoice}
                  className="bg-black text-white dark:bg-white dark:text-black p-6 rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all flex items-center gap-4"
                  title="Print or Save as PDF"
                >
                  <Printer size={24} />
                  <span className="font-black text-xs uppercase tracking-widest">PRINT PDF</span>
                </button>
                <button 
                  onClick={() => downloadAsJSON(currentInvoice)}
                  className="bg-white border border-gray-200 dark:bg-zinc-900 dark:border-zinc-800 p-4 rounded-full shadow-lg hover:scale-110 transition-all text-black dark:text-white"
                  title="Export to JSON"
                >
                  <Download size={20} />
                </button>
             </div>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

