               <div>
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-400 mb-6">Contrast Point</h4>
                  <div className="flex flex-wrap gap-4">
                     {ACCENT_COLORS.map(c => (
                       <button key={c.value} onClick={() => setInvoice({...invoice, accentColor: c.value})} className={`w-12 h-12 rounded-full transition-all border-2 ${invoice.accentColor === c.value ? 'border-black dark:border-white scale-110' : 'border-transparent'}`} style={{ backgroundColor: c.value }} />
                     ))}
                  </div>
               </div>
            </div>
          )}
        </div>
      </div>
